import "./QuickActions.css";

const QuickActions = () => {

    return (

        <div className="quick-card">

            <h2>Quick Actions</h2>

            <button>Add Employee</button>

            <button>Mark Attendance</button>

            <button>Apply Leave</button>

            <button>Generate Payroll</button>

        </div>

    );

};

export default QuickActions;
